#include<bits/stdc++.h>
using namespace std;
map<string,int> mp;
map<string,int>::iterator it;
int main(void){
	int n,Max=0;string s,str,MaxName;
	cin>>n>>s;
	for(int i=0;i<s.size()-1;i++){
		str="",str+=s[i],str+=s[i+1];
		if(!(mp.count(str))) mp[str]=1;
		else mp[str]++;
	}
	for(it=mp.begin();it!=mp.end();it++){
		if(it->second>Max){
			Max=it->second;
			MaxName=it->first;
		}
	}
	cout<<MaxName;
	return false;
}
